app = new App();
app.use((req, next) => { order.push("m1"); return next(); });
app.use((req, next) => { order.push("m2"); return next(); });
app.get("/x", req => { order.push("handler"); return { status: 200, body: "x" }; });
let r = app.handle({ method: "GET", path: "/x" });
eq(order, ["m1","m2","handler"], "middleware order before handler");
