eq(app.handle({ method: "POST", path: "/only-get" }), { status: 404, body: "Not Found" }, "method mismatch 404");
eq(app.handle({ method: "GET", path: "/nope" }), { status: 404, body: "Not Found" }, "path mismatch 404");

// 4. handler return value is the response (no middleware)
app = new App();
app.post("/p", req => ({ status: 201, body: "created" }));
eq(app.handle({ method: "POST", path: "/p" }), { status: 201, body: "created" }, "handler return is response");

console.log("\nPASS:", pass, "FAIL:", fail);
